import React from "react";
import { Card, Row } from "react-bootstrap";
import { getAllSocialAccounts, getCityAndState, getEmail, getFullName, getProfile, } from "../../utilities";
import { SocialAccount } from "../common/SocialAccount";
import { TextIcon } from "../common/TextIcon";

export const Introduction = () => {
  const name = getFullName();
  const profile = getProfile();
  const city = getCityAndState();
  const email = getEmail();

  return (
    <>
      <Card className="text-center">
        <Card.Body>
          <Row>
            <Card.Title>
              <p className="h1">{name}</p>
            </Card.Title>
            <Card.Subtitle>
              <p className="h5 text-muted">{profile}</p>
            </Card.Subtitle>
            <Card.Text style={{paddingBottom: "0.5rem"}}>
              <TextIcon name="at" size="lg" text={email} />
              <TextIcon name="map-marker-alt" size="lg" text={city} />
            </Card.Text>
          </Row>
          <Row>
            <Card.Text>
              {getAllSocialAccounts().map((item) => (
                <SocialAccount key={`social-${item.rank}`} social={item} />
              ))}
            </Card.Text>
          </Row>
        </Card.Body>
      </Card>
    </>
  );
};
