import React from "react";
import { Card, Row } from "react-bootstrap";
import { getEducationHistory } from "../../utilities";
import { EducationTile } from "./EducationTile";

export const Education = () => {
  const history = getEducationHistory();
  return (
    <Card>
      <Card.Header>Education</Card.Header>
      <Card.Body>
        <Row style={{overflowX: "scroll", width: "auto"}}>
          {history.map((item, index) => (
            <EducationTile key={`education-tile-${index}`} education={item} />
          ))}
        </Row>
      </Card.Body>
    </Card>
  );
};
